def assess(record: dict) -> str:
    required = {'case_id', 'tasks', 'slices', 'rubric_levels', 'holdout'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (sum(record["slices"].values()) != record["tasks"] or record["holdout"] == 0)) else "REBUILD_EVAL_DATASET"

valid = {'case_id': 'CASO-ICA-050-1A', 'holdout': 10, 'rubric_levels': {0, 1, 2, 3}, 'slices': {'adversarial': 5, 'edge': 10, 'normal': 25}, 'tasks': 40}
invalid = {'case_id': 'CASO-ICA-050-1A', 'holdout': 10, 'rubric_levels': {0, 1, 2, 3}, 'slices': {'adversarial': 5, 'edge': 10, 'normal': 25}, 'tasks': 0}
incomplete = {**valid}
incomplete.pop('holdout', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

